import{_ as a,o,c as i,a0 as c}from"./chunks/framework.ECMusB9M.js";const m=JSON.parse('{"title":"3. Acciones","description":"","frontmatter":{"layout":"default","title":"3. Acciones"},"headers":[],"relativePath":"03_acciones.md","filePath":"03_acciones.md"}'),s={name:"03_acciones.md"};function l(n,e,r,t,d,u){return o(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="_3-acciones-del-plan-operativo" tabindex="-1">3. Acciones del plan operativo <a class="header-anchor" href="#_3-acciones-del-plan-operativo" aria-label="Permalink to &quot;3. Acciones del plan operativo&quot;">​</a></h1><h2 id="_3-1-producto-servicio-ficha-02" tabindex="-1">3.1. Producto / Servicio (Ficha 02) <a class="header-anchor" href="#_3-1-producto-servicio-ficha-02" aria-label="Permalink to &quot;3.1. Producto / Servicio (Ficha 02)&quot;">​</a></h2><h3 id="caracteristicas" tabindex="-1">Características <a class="header-anchor" href="#caracteristicas" aria-label="Permalink to &quot;Características&quot;">​</a></h3><p>La aplicación consiste en un sistema de seguimiento que permita centralizar los datos de los pacientes y ayudar a los profesionales a gestionar y analizar los datos de sus pacientes de forma digital.</p><p>Las principales características de la aplicación son:</p><ul><li>Para el paciente, un panel de control para gestionar los datos del paciente.</li><li>Para el profesional, un panel de control para gestionar los datos del paciente.</li><li>Los datos se almacenan en el dispositivo del usuario de forma local y se exportan en formato CSV.</li></ul><h3 id="diseno-y-valor-anadido" tabindex="-1">Diseño y valor añadido <a class="header-anchor" href="#diseno-y-valor-anadido" aria-label="Permalink to &quot;Diseño y valor añadido&quot;">​</a></h3><ul><li>Se ofrece un acceso seguro a los datos del usuario mediante una autenticación con Google.</li><li>Navegación intuitiva y amigable, queremos no abrumar al usuario con demasiada información.</li><li>Análisis automático de patrones.</li><li>Sincronización con la nube para que el profesional pueda acceder a los datos desde cualquier dispositivo.</li><li>Autenticación de usuarios con Google.</li></ul><h2 id="_3-2-precio-ficha-03" tabindex="-1">3.2. Precio (Ficha 03) <a class="header-anchor" href="#_3-2-precio-ficha-03" aria-label="Permalink to &quot;3.2. Precio (Ficha 03)&quot;">​</a></h2><h3 id="_3-2-1-justificacion" tabindex="-1">3.2.1. Justificación <a class="header-anchor" href="#_3-2-1-justificacion" aria-label="Permalink to &quot;3.2.1. Justificación&quot;">​</a></h3><p>Queremos resolver este problema creando una aplicación que permita a los psicólogos y terapeutas gestionar y analizar los datos de sus pacientes de forma digital y a los pacientes que puedan ver sus datos en un solo lugar.</p><h3 id="_3-2-2-modelo-saas-software-as-a-service" tabindex="-1">3.2.2. Modelo SaaS (Software as a Service) <a class="header-anchor" href="#_3-2-2-modelo-saas-software-as-a-service" aria-label="Permalink to &quot;3.2.2. Modelo SaaS (Software as a Service)&quot;">​</a></h3><p>La aplicación se ofrecerá mediante un <strong>modelo de suscripción online</strong>, lo que facilita el acceso inmediato y seguro para los profesionales, asegurando la escalabilidad del proyecto a otras asociaciones o profesionales del sector.</p><ul><li>Estrategia de precios</li><li>Política de descuentos</li></ul><h3 id="_3-3-distribucion-ficha-04" tabindex="-1">3.3. Distribución (FICHA 04) <a class="header-anchor" href="#_3-3-distribucion-ficha-04" aria-label="Permalink to &quot;3.3. Distribución (FICHA 04)&quot;">​</a></h3><p>Nuestro <code>canal de distribución</code> será <strong>directo y digital</strong>.</p><p>El producto se desarrolla y se entrega directamente a la asociación <strong>SEMBREM</strong> como <code>cliente inicial</code>, sin <code>intermediarios comerciales</code>.</p><ol><li>No existen <code>mayoristas</code>.</li><li>No existen <code>minoristas</code>.</li><li>Somos <code>desarrolladores</code> del servicio y lo ofrecemos directamente al <code>cliente profesional</code>.</li></ol><h4 id="canal-directo" tabindex="-1">Canal directo <a class="header-anchor" href="#canal-directo" aria-label="Permalink to &quot;Canal directo&quot;">​</a></h4><p>Nos encargamos de todo el desarrollo y la distribución de la app, asegurando que cada función cumpla con las necesidades de nuestros clientes.</p><ol><li>Somos los <code>desarrolladores</code> de la aplicación.</li><li>La distribuimos directamente a la <code>asociación cliente</code>.</li><li>En la fase inicial, el proyecto se implementa para <strong>SEMBREM</strong> como <code>cliente piloto</code>.</li></ol><h5 id="acceso-online" tabindex="-1">Acceso online <a class="header-anchor" href="#acceso-online" aria-label="Permalink to &quot;Acceso online&quot;">​</a></h5><p>La distribución es completamente <code>digital</code>, lo que facilita el acceso inmediato y seguro para los profesionales que utilicen la app. La aplicación se ofrecerá mediante:</p><ol><li><code>Página web corporativa</code></li><li><code>Acceso online</code> a la plataforma</li><li><code>Modelo de suscripción</code> (en fases futuras)</li></ol><p>No existe <code>tienda física</code>, ya que se trata de un <code>producto digital</code>.</p><h4 id="nuevas-formas-de-distribucion" tabindex="-1">Nuevas formas de distribución <a class="header-anchor" href="#nuevas-formas-de-distribucion" aria-label="Permalink to &quot;Nuevas formas de distribución&quot;">​</a></h4><p>En una fase futura, el producto podrá contratarse mediante <code>suscripción online</code> desde la <code>página web</code>. Esto permitirá su <code>escalabilidad</code> a otras asociaciones o profesionales del sector.</p><ol><li>Contratación mediante <code>suscripción online</code>.</li><li>Escalabilidad a otras asociaciones o profesionales del sector.</li></ol><h3 id="_3-4-comunicacion-ficha-04" tabindex="-1">3.4. Comunicación (FICHA 04) <a class="header-anchor" href="#_3-4-comunicacion-ficha-04" aria-label="Permalink to &quot;3.4. Comunicación (FICHA 04)&quot;">​</a></h3><p>Para dar a conocer la app, nos centraremos en <strong>canales digitales y profesionales</strong>, que nos permitan llegar directamente a los <code>psicólogos</code> y <code>asociaciones</code> interesadas.</p><p>Entre los principales medios se incluyen:</p><ul><li><code>Internet</code> y <code>página web corporativa</code>.</li><li><code>Mailing</code> dirigido a profesionales y asociaciones del sector.</li><li><code>Redes sociales</code>, como <code>LinkedIn</code> y grupos especializados de psicología.</li></ul><h4 id="material-de-promocion" tabindex="-1">Material de promoción <a class="header-anchor" href="#material-de-promocion" aria-label="Permalink to &quot;Material de promoción&quot;">​</a></h4><p>Elaboraremos un <strong>folleto digital de una página</strong> que resuma los beneficios, precios y datos de contacto. También diseñaremos una <strong>tarjeta de visita digital</strong>, logotipos, banners y <code>mockups</code> de la app para reforzar la imagen profesional.</p><h4 id="promocion-de-ventas-y-fidelizacion" tabindex="-1">Promoción de ventas y fidelización <a class="header-anchor" href="#promocion-de-ventas-y-fidelizacion" aria-label="Permalink to &quot;Promoción de ventas y fidelización&quot;">​</a></h4><p>Para animar a probar la app, ofreceremos:</p><ul><li>Acceso de <code>prueba gratuita</code> para psicólogos o asociaciones.</li><li><code>Webinars</code> y demostraciones online.</li><li>Participación en <code>eventos profesionales</code> del sector.</li></ul><p>Mantendremos una relación cercana mediante <code>newsletters</code>, soporte personalizado y recogida de <code>feedback</code>.</p><h4 id="relaciones-publicas-y-venta-directa" tabindex="-1">Relaciones públicas y venta directa <a class="header-anchor" href="#relaciones-publicas-y-venta-directa" aria-label="Permalink to &quot;Relaciones públicas y venta directa&quot;">​</a></h4><p>Reforzaremos nuestra reputación mediante:</p><ul><li><code>Patrocinio</code> de eventos o jornadas de psicología.</li><li>Colaboración en <code>publicaciones</code> sobre bienestar digital.</li><li>Presentaciones directas a asociaciones como <code>SEMBREM</code> por parte de nuestro equipo.</li></ul><h3 id="_3-5-plan-de-atencion-al-cliente-ficha-05" tabindex="-1">3.5. Plan de atención al cliente (FICHA 05) <a class="header-anchor" href="#_3-5-plan-de-atencion-al-cliente-ficha-05" aria-label="Permalink to &quot;3.5. Plan de atención al cliente (FICHA 05)&quot;">​</a></h3><ul><li>Organización de la atención al cliente</li><li>Gestión de reclamaciones y sugerencias</li><li>Encuestas de satisfacción</li></ul>',43)])])}const h=a(s,[["render",l]]);export{m as __pageData,h as default};
